	('profile:nancy', '{"id": "nancy", "data": {"stats": {"examDate": null, "streakBest": 0, "dailyTarget": null, "dailyHistory": [], "totalCorrect": 0, "streakCurrent": 0, "totalAttempted": 0, "lastStudiedDate": null, "streakGraceAvailable": true}, "history": {}, "bookmarks": [], "preferences": {"quickCount": 5, "quickTopic": "fund", "reviewDismissedDate": null, "reviewRemindersEnabled": true}, "revisionLog": [], "disabledBanks": {}, "customQuestions": [{"q": "A patient in the emergency department with an acute asthma exacerbation has severe wheezing and shortness of breath. What is the most appropriate initial action to manage this patient''s condition?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-46cuj", "exp": "Acute wheezing is caused by reversible bronchospasm, so the first-line, fastest-acting intervention is an inhaled/nebulised short-acting bronchodilator (e.g. salbutamol). Oxygen and steroids are given too, but the bronchodilator directly relieves the obstruction. Key takeaway: in acute asthma, open the airway first — nebulised bronchodilator.", "sub": "Respiratory Emergency", "type": "mcq", "topic": "msn", "wrong": {"1": "Corticosteroids reduce airway inflammation but act over hours, not minutes — not the initial rescue.", "3": "Intubation is a last resort for impending respiratory failure, not the initial step for wheezing."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["Administer a high-flow oxygen mask at 10 L/min", "Start intravenous corticosteroids immediately", "Provide a nebulised bronchodilator treatment", "Prepare for intubation and mechanical ventilation"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "On assessment a patient''s apical pulse is 80/min and the radial pulse is 65/min. What is the pulse deficit?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-q3zsm", "exp": "Pulse deficit = apical rate − radial rate = 80 − 65 = 15. It means 15 beats per minute aren''t producing a palpable peripheral pulse (classically in atrial fibrillation). Key takeaway: pulse deficit = apical − radial, counted at the same time by two people.", "sub": "Vital Signs", "type": "mcq", "topic": "fund", "wrong": {"0": "10 would require a radial of 70.", "2": "25 would require a radial of 55."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["10", "15", "25", "35"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A nurse assessing a newborn with an APGAR of 7 at 1 minute notices that the corner of the neonate''s mouth is stained with meconium secretions. What should be the next step of management?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-0r9sp", "exp": "Meconium around the mouth means the airway must be cleared first — suction the mouth, then the nose — to prevent meconium aspiration as the baby breathes. With APGAR 7 the baby is not severely depressed, so aggressive resuscitation isn''t yet indicated. Key takeaway: airway clearance (mouth before nose) precedes everything in a meconium-stained newborn.", "sub": "Neonatal Resuscitation", "type": "mcq", "topic": "peds", "wrong": {"0": "Full resuscitation is for a depressed baby (low APGAR/no respiratory effort), not one scoring 7.", "3": "Routine care ignores the aspiration risk the meconium poses."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["Prepare for resuscitation", "Inform the physician", "Perform suctioning of mouth and nose", "Perform routine care"], "difficulty": "hard", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A child with diarrhoea has sunken eyes and is thirsty; when offered fluid the child drinks eagerly. Using IMNCI, which category of dehydration does this child have?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-3dno9", "exp": "Under IMNCI, sunken eyes plus drinking eagerly/thirsty (restless or irritable) = ''some dehydration''. ''Severe'' would show lethargy/unconsciousness or inability to drink. Key takeaway: drinks eagerly = some dehydration; too weak/lethargic to drink = severe.", "sub": "IMNCI / Dehydration", "type": "mcq", "topic": "peds", "wrong": {"0": "''No dehydration'' shows none of these danger signs.", "2": "''Severe'' needs lethargy/unconsciousness or inability to drink, absent in this alert, eagerly-drinking child."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["No dehydration", "Some dehydration", "Severe dehydration", "Normal"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A patient is hyperventilating and their CO2 level is below the normal range. The priority nursing intervention for this patient is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-r4xwn", "exp": "Hyperventilation blows off CO2, causing respiratory alkalosis (tingling, dizziness, carpopedal spasm). Re-breathing into a paper bag lets the patient inhale their own exhaled CO2, raising it back to normal. Key takeaway: hyperventilation + low CO2 = paper-bag re-breathing.", "sub": "Acid-Base / Respiratory", "type": "mcq", "topic": "msn", "wrong": {"1": "Giving oxygen does nothing for an already over-oxygenated, low-CO2 state.", "3": "Sedating masks the cause and risks depressing respiration."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Encouraging paper-bag breathing", "Giving O2 directly", "Informing the doctor", "Giving a sedative"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "Which of the following is considered the best position for performing a lumbar puncture in an adult client?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-68u25", "exp": "The lateral recumbent position with knees drawn up to the chest and chin tucked (classically left lateral, fetal position) flexes the spine and widens the interspinous spaces for needle entry. Key takeaway: LP = curl up like a ''C'' on your side to open the vertebral gaps.", "sub": "Lumbar Puncture", "type": "mcq", "topic": "fund", "wrong": {"2": "Fowler''s (sitting/semi-upright) doesn''t flex the lumbar spine the same way and is less standard for adults.", "3": "Prone gives no access to the lumbar interspaces."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Left lateral (knees drawn to chest)", "Right lateral", "Fowler''s position", "Prone position"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "Which of the following is a contraindication of nasotracheal intubation?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-7w8r1", "exp": "With a base-of-skull fracture, a nasal tube can be misdirected through the fracture into the cranial cavity — hence nasotracheal (and nasogastric) routes are contraindicated. Key takeaway: base-of-skull fracture = no tubes through the nose.", "sub": "Airway Management", "type": "mcq", "topic": "msn", "wrong": {"2": "Limited mouth opening is actually a reason to PREFER the nasal route over oral intubation.", "3": "An intraoral mass favours the nasal route too, not contraindicates it."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["Conscious patient", "Fracture of base of skull", "Patient with limited mouth opening", "Intraoral mass"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "In a 35-year-old woman, USG shows a 2 mm mass and CA-125 is reactive (raised). What is the suspected diagnosis?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-vj42r", "exp": "CA-125 is the classic tumour marker for epithelial ovarian carcinoma. A raised CA-125 with an adnexal/ovarian mass points to ovarian cancer. Key takeaway: CA-125 → ovary.", "sub": "Tumour Markers", "type": "mcq", "topic": "obg", "wrong": {"1": "Cervical cancer is linked to HPV and screened by Pap/VIA, not CA-125.", "3": "Endometrial (uterine) cancer presents with postmenopausal bleeding and isn''t CA-125-defined."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Ovarian cancer", "Cervical cancer", "Mucosal cancer", "Uterine cancer"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A 32-week pregnant woman presents with abdominal pain, uterine tenderness, and signs of fetal distress. Which condition should the nurse suspect first?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-5niqz", "exp": "Painful third-trimester presentation with a tender, often rigid uterus and fetal distress is classic abruptio placentae (premature separation of a normally sited placenta). Key takeaway: painful + tender uterus = abruption; painless bleed = praevia.", "sub": "Antepartum Haemorrhage", "type": "mcq", "topic": "obg", "wrong": {"1": "Placenta praevia causes painless bleeding with a soft, non-tender uterus.", "3": "Ectopic pregnancy presents in the first trimester, not at 32 weeks."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Abruptio placentae", "Placenta praevia", "Abortion", "Ectopic pregnancy"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A 5-year-old child drank kerosene accidentally. What is the priority management?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-qtbjb", "exp": "Kerosene is a volatile hydrocarbon; inducing vomiting or lavage risks aspiration and severe chemical pneumonitis, and charcoal binds hydrocarbons poorly. The safe priority is to avoid anything that could cause aspiration — keep nil-by-mouth and give supportive care while arranging help. Key takeaway: hydrocarbon ingestion = do NOT induce emesis or lavage.", "sub": "Poisoning", "type": "mcq", "topic": "peds", "wrong": {"0": "Lavage risks aspiration of the hydrocarbon into the lungs.", "2": "Inducing vomiting is exactly what causes the dangerous aspiration."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["Gastric lavage", "Keep nil-by-mouth until help arrives", "Induce vomiting", "Give activated charcoal"], "difficulty": "hard", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "According to IMNCI, a danger sign of a sick young baby includes:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-e3zio", "exp": "IMNCI general danger signs are: unable to drink/breastfeed, vomits everything, convulsions, and lethargy/unconsciousness. ''Vomits everything'' (persistent vomiting) is one of them. Key takeaway: the four danger signs spell urgent referral — can''t feed, vomits everything, convulsions, lethargic.", "sub": "IMNCI Danger Signs", "type": "mcq", "topic": "peds", "wrong": {"2": "Fever alone is classified and treated, but isn''t itself a general danger sign.", "3": "Watery eyes is not an IMNCI danger sign."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Persistent vomiting (vomits everything)", "Soles and palms yellow in colour", "Fever", "Watery eyes"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A patient in the ward suffers sudden cardiac arrest with no evidence of spinal cord injury. Which method should be used to open the airway for intubation?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-bid0r", "exp": "With no suspected spinal injury, head-tilt/chin-lift is the preferred manoeuvre to open the airway. Jaw-thrust is reserved for suspected cervical-spine injury (it avoids moving the neck). Key takeaway: no spinal injury = head-tilt/chin-lift; suspected spinal injury = jaw-thrust.", "sub": "Airway Management", "type": "mcq", "topic": "msn", "wrong": {"0": "Jaw-thrust is for SUSPECTED spinal injury, which is explicitly absent here.", "3": "Heimlich is for choking on a foreign body, not for opening an arrest patient''s airway."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["Jaw-thrust method", "Head-tilt, chin-lift method", "Valsalva manoeuvre", "Heimlich manoeuvre"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A child is on chemotherapy. The nurse should teach the mother about all of the following, EXCEPT:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-vrvdt", "exp": "Chemotherapy causes immunosuppression, so teaching centres on infection prevention: hand hygiene, avoiding crowds, gentle oral care. A sitz bath (warm water immersion of the perineum) is unrelated to this child''s care and can introduce infection risk — so it''s the exception. Key takeaway: chemo teaching = protect from infection; sitz bath doesn''t belong.", "sub": "Oncology Nursing", "type": "mcq", "topic": "peds", "wrong": {"0": "Hand washing is core infection prevention in neutropenia.", "1": "Avoiding crowds limits exposure to infection in an immunosuppressed child."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [3], "options": ["Hand washing", "Avoid crowded places", "Brush teeth twice a day", "Sitz bath"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A furosemide injection is administered to a patient for which of the following actions?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-wcvbs", "exp": "Furosemide is a loop diuretic (acts on the ascending loop of Henle) used to remove excess fluid — in heart failure, oedema and fluid overload. Key takeaway: furosemide = loop diuretic = offloads excess fluid.", "sub": "Diuretics", "type": "mcq", "topic": "pharm", "wrong": {"1": "ACE inhibitors (e.g. enalapril) act on the renin-angiotensin system, not as diuretics.", "3": "Furosemide is a loop, not a thiazide, diuretic — different site and potency."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["A loop diuretic to prevent excessive fluid volume", "Acts as an ACE inhibitor", "Prevents gastric movement", "Is a thiazide diuretic"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A nurse receives a road-traffic-accident (RTA) patient in the emergency room. By which method should oxygen be administered to this patient?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-frmh0", "exp": "A trauma/RTA patient needs high-concentration oxygen; the non-rebreather mask delivers the highest FiO2 (~60–90%) of these options via its reservoir bag and one-way valves. Key takeaway: trauma/shock = high-flow O2 via non-rebreather mask.", "sub": "Trauma / Oxygenation", "type": "mcq", "topic": "msn", "wrong": {"0": "A simple mask delivers only moderate FiO2 — not enough for major trauma.", "2": "A nasal cannula gives the lowest oxygen concentration."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [3], "options": ["Simple mask", "Partial re-breather mask", "Nasal cannula", "Non-rebreather mask"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "In a patient with a 20% burn, how should the nurse monitor the fluid volume?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-347uc", "exp": "In major burns, fluid resuscitation is titrated to urine output, so strict intake-output monitoring (especially hourly urine output) is the key measure of fluid balance and renal perfusion. Key takeaway: in burns, urine output (via strict I&O) tells you if resuscitation is working.", "sub": "Burns", "type": "mcq", "topic": "msn", "wrong": {"0": "Daily weight is too slow to guide minute-to-minute burn resuscitation.", "1": "Skin integrity assesses the wound, not fluid status."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["Weight", "Skin integrity", "Strict intake and output", "Height"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "Hypokalaemia is seen in:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-wrezx", "exp": "Prolonged nasogastric suction removes potassium- and acid-rich gastric fluid, producing hypokalaemia (and metabolic alkalosis). Key takeaway: NG suction drains K+ and H+ → hypokalaemia + alkalosis.", "sub": "Electrolytes", "type": "mcq", "topic": "msn", "wrong": {"0": "Burns (with tissue breakdown) tend to release potassium, causing hyperkalaemia early.", "2": "Addison''s disease causes HYPERkalaemia (low aldosterone retains potassium)."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [3], "options": ["Burns", "Increased uric acid", "Addison''s disease", "Nasogastric suction"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "Which behaviour therapy technique is most appropriate for a patient suffering from pain and stiffness?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-moua1", "exp": "Relaxation training (progressive muscle relaxation, breathing) reduces the muscle tension and sympathetic arousal that amplify pain and stiffness, and is a standard behavioural pain-management technique. Key takeaway: pain/stiffness → relaxation training breaks the tension–pain cycle.", "sub": "Behaviour Therapy", "type": "mcq", "topic": "mhn", "wrong": {"0": "Hypnosis can help pain but isn''t the first-line behavioural technique taught for general stiffness.", "2": "Meditation aids stress but relaxation training targets the muscular tension directly."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["Hypnosis", "Relaxation", "Meditation", "Masturbation"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "After a blood transfusion, signs and symptoms of circulatory (volume) overload include:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-db22y", "exp": "Transfusion-associated circulatory overload (TACO) is fluid overload: tachycardia, tachypnoea/dyspnoea, raised JVP, crackles and hypertension. Key takeaway: TACO = the signs of a full, overloaded circulation (fast heart, fast breathing, distended neck veins).", "sub": "Transfusion Reaction", "type": "mcq", "topic": "msn", "wrong": {"2": "Bradycardia + hypotension + fever fits a different picture, not volume overload.", "3": "Hypotension + fever suggests a haemolytic/septic reaction, not circulatory overload (which raises BP)."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Tachycardia, tachypnoea, jugular venous distension", "Bradycardia, hypertension, fever", "Bradycardia, hypotension, fever", "Tachycardia, fever, hypotension"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A nurse uses a DPT vaccine and finds that the vial has granules (flocculation). What is the next nursing action?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-zrm4o", "exp": "Granules/flocculation in DPT indicate the vaccine has been frozen and damaged (the Shake Test would show sediment that doesn''t resuspend). A freeze-damaged adsorbed vaccine must be discarded — it cannot be salvaged by shaking. Key takeaway: flocculated/frozen DPT = discard, never use.", "sub": "Cold Chain / Vaccines", "type": "mcq", "topic": "peds", "wrong": {"1": "Shaking won''t reverse freeze damage; the clumps settle back (failed shake test).", "3": "Using a freeze-damaged vaccine risks an ineffective/unsafe dose."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Discard the vial", "Shake vigorously", "Check after 15 minutes", "Keep using the vial"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A patient is in the post-operative area after a right-side mastectomy. What should be the priority care for this patient?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-pvovu", "exp": "After mastectomy (with axillary node disruption), the affected arm has impaired lymphatic drainage; BP cuffs, venipuncture and constriction on that side risk lymphoedema and infection. So BP is taken on the unaffected (left) side. Key takeaway: nothing constricting on the mastectomy side — BP/IV go to the other arm.", "sub": "Post-Mastectomy Care", "type": "mcq", "topic": "msn", "wrong": {"0": "Taking BP on the operated (right) side risks lymphoedema — the thing to avoid.", "3": "Pulse oximetry isn''t the priority concern here, and the affected side should be spared regardless."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["Take BP from the right side", "Take BP from the left side", "Attach pulse oximetry on the left side", "Attach pulse oximetry on the right side"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "EMLA, a topical anaesthetic, should be applied how long before the procedure?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-72ma3", "exp": "EMLA cream needs roughly 60 minutes under occlusion to penetrate intact skin and produce adequate dermal anaesthesia before a needle procedure. Key takeaway: EMLA = apply about 1 hour ahead.", "sub": "Topical Anaesthesia", "type": "mcq", "topic": "fund", "wrong": {"0": "10 minutes is far too short for skin penetration.", "3": "Applied immediately, it has no time to work."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["10 minutes", "30 minutes", "60 minutes", "Immediately before the procedure"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "While choosing a blood-pressure cuff for an adult, the correct ratio of the bladder length to width is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-o9ku4", "exp": "A correctly sized cuff bladder is about 80% of arm circumference in length and about 40% in width, giving a length-to-width ratio of about 2:1. Key takeaway: BP cuff bladder length : width ≈ 2 : 1 (80% long, 40% wide).", "sub": "Blood Pressure Measurement", "type": "mcq", "topic": "fund", "wrong": {"2": "1:2 reverses the relationship (would make it wider than long).", "3": "3:1 is too long relative to width."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["1:3", "2:1", "1:2", "3:1"], "difficulty": "hard", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "The smallest syringe size that should be used for the first use of a central venous access device is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-uxva9", "exp": "Smaller syringes create higher injection pressure, which can rupture a central catheter; a 10 mL (or larger) syringe is recommended to keep pressure safe. Key takeaway: central lines need >=10 mL syringes — bigger barrel, lower pressure.", "sub": "Central Venous Access", "type": "mcq", "topic": "fund", "wrong": {"1": "1 mL generates dangerously high pressure for a central catheter.", "2": "2 mL is still too small — pressure remains high."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [3], "options": ["5 mL", "1 mL", "2 mL", "10 mL"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "What flow rate should be set when using a resuscitation (bag-valve) device?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-q7ce8", "exp": "A bag-valve-mask with reservoir is run at about 15 L/min to keep the reservoir filled and deliver close to 100% oxygen during resuscitation. Key takeaway: BVM oxygen flow = 15 L/min.", "sub": "Resuscitation", "type": "mcq", "topic": "fund", "wrong": {"0": "10 L/min may not keep the reservoir adequately filled for near-100% delivery.", "3": "8 L/min is too low for effective resuscitation oxygen delivery."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["10 L/min", "9 L/min", "15 L/min", "8 L/min"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "After taking blood from the blood bank, the transfusion should be started within:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-7ql43", "exp": "Blood must be started within 30 minutes of leaving the blood bank''s controlled refrigeration; beyond this, warming raises the risk of bacterial growth and haemolysis. Key takeaway: hang blood within 30 minutes of collection from the bank.", "sub": "Blood Transfusion", "type": "mcq", "topic": "fund", "wrong": {"1": "60 minutes exceeds the safe out-of-fridge window for starting.", "3": "There IS a strict time limit — leaving blood unrefrigerated is unsafe."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["30 minutes", "60 minutes", "90 minutes", "No such time limit"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "Which of the following is an indication to perform suctioning?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-l5sr5", "exp": "Suctioning is indicated when secretions impair ventilation — shown by falling oxygen saturation (plus audible/visible secretions, coarse crackles, rising airway pressures). A patient with an effective cough can clear secretions themselves. Key takeaway: suction for a problem (low SpO2/secretions), not routinely.", "sub": "Airway Suctioning", "type": "mcq", "topic": "fund", "wrong": {"0": "Normal air entry means no obstruction needing suction.", "1": "An effective cough clears secretions on its own — no suction needed."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["Normal air entry on auscultation", "The patient has an effective cough", "Reduced oxygen saturation levels", "Normal respiratory rate"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A client with heart failure is dyspnoeic with crackles on auscultation. Which symptom would manifest for a client with EXCESS fluid volume?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-06epn", "exp": "Fluid volume excess raises circulating volume: hypertension, raised CVP, distended neck/hand veins, crackles, oedema and weight GAIN. Hypertension is the fitting sign here. Key takeaway: overload = high pressures, full veins, weight gain (the opposite of the other options).", "sub": "Heart Failure / Fluid Volume", "type": "mcq", "topic": "msn", "wrong": {"0": "Decreased CVP and flat veins indicate fluid DEFICIT, not excess.", "3": "Weight loss reflects fluid loss; overload causes weight gain."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["Decreased central venous pressure", "Flat neck and hand veins", "Hypertension", "Weight loss"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "The recommended protocol the nurse follows for preventing constipation when starting a patient on opioids is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-5ob3a", "exp": "Opioids reduce gut motility, so prophylaxis pairs a stimulant laxative (to restore motility) with a stool softener — started WITH the opioid. Bulk fibre can worsen impaction if motility is already slowed. Key takeaway: opioid + scheduled stimulant laxative ± softener from day one.", "sub": "Opioid Side-Effects", "type": "mcq", "topic": "pharm", "wrong": {"0": "Bulk fibre without motility can worsen obstruction in opioid-slowed bowels.", "1": "Enemas treat established constipation; they''re not first-line prevention."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [3], "options": ["Adding bulk fibre to the diet", "Giving enemas as needed", "Increasing fluids and exercise", "Using a bowel stimulant and a stool softener"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "Which of the following is the correct way to measure the size of an oropharyngeal airway (OPA)?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-cfpbe", "exp": "An OPA is sized from the corner of the mouth to the angle of the jaw (mandible) or earlobe. Measuring from the nose belongs to the nasopharyngeal airway (NPA), not the OPA. Key takeaway: OPA = mouth corner to jaw angle; NPA = nostril to tragus/earlobe.", "sub": "Oropharyngeal Airway", "type": "mcq", "topic": "msn", "wrong": {"2": "Tip of nose to angle of mandible is a nasopharyngeal-airway-style measurement.", "3": "Ala of nose to angle of mandible is also a nasal-airway measurement, not OPA."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["Tragus to angle of mouth", "Corner of the mouth to the angle of the jaw", "Tip of nose to angle of mandible", "Ala of nose to angle of mandible"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "An oropharyngeal airway is used in which of the following patients?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-u3sjk", "exp": "An OPA can only be used in an unconscious patient with no gag reflex; in a conscious/semi-conscious patient it provokes gagging, vomiting and aspiration. Key takeaway: OPA only when there''s no gag reflex (unconscious).", "sub": "Oropharyngeal Airway", "type": "mcq", "topic": "msn", "wrong": {"1": "A semi-conscious patient may still gag and aspirate.", "2": "A conscious patient will gag/vomit on an OPA."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Unconscious", "Semi-conscious", "Conscious", "All of the above"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "While administering medication to prevent error, patient identification is done by:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-iru6x", "exp": "Safe medication identification uses two patient identifiers (name AND date of birth), verified against the ID band and the medication chart/order. The most complete option meets all these checks. Key takeaway: two identifiers + ID band + chart cross-check before giving any drug.", "sub": "Patient Safety", "type": "mcq", "topic": "fund", "wrong": {"1": "Name alone is a single identifier — two are required (add DOB).", "2": "Misses the date-of-birth identifier and the chart cross-check."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Patient tells their name and date of birth, check the medication chart and check the patient identification band", "Patient tells their name, check the medication chart and check the identification band", "Patient tells their name, and check the patient identification band", "Patient tells their name, patient identification band"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A 28-year-old woman presents with hirsutism and male-pattern body hair. Which test should be done?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-b4xfk", "exp": "Hirsutism most often reflects androgen excess/PCOS; transvaginal ultrasound (TVS) identifies polycystic ovarian morphology, one of the Rotterdam criteria, and is a key investigation (alongside androgen assays). Key takeaway: hirsutism workup includes TVS USG to look for polycystic ovaries. (Serum testosterone/androgens are also used.)", "sub": "Hirsutism / PCOS", "type": "mcq", "topic": "obg", "wrong": {"0": "FSH is usually normal/low in PCOS and doesn''t confirm the diagnosis alone.", "3": "Progesterone assesses ovulation/luteal phase, not the cause of hirsutism."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["FSH", "LH", "TVS USG", "Progesterone"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A G3P2 woman has had 2 previous Caesarean sections. What is the approximate risk of uterine rupture in this woman?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-2ks3h", "exp": "Uterine rupture risk in a trial of labour is low — on the order of a few percent; with multiple prior Caesareans it rises modestly into roughly the 2–3% range. The double-digit figures are far too high. Key takeaway: prior-Caesarean rupture risk is small (low single digits), which is why TOLAC is offered selectively. (Exact figures vary by source.)", "sub": "VBAC / Uterine Rupture", "type": "mcq", "topic": "obg", "wrong": {"2": "10–12% greatly overstates the rupture risk.", "3": "46% is implausibly high for scar rupture."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["2–3%", "5–7%", "10–12%", "46%"], "difficulty": "hard", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "The normal chest-compression to ventilation ratio (adult) is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-zkkt0", "exp": "The standard adult CPR ratio is 30 compressions to 2 ventilations (single or two-rescuer for adults). Key takeaway: adult CPR = 30:2. (Neonatal resuscitation is 3:1; two-rescuer paediatric is 15:2.)", "sub": "CPR", "type": "mcq", "topic": "fund", "wrong": {"1": "15:2 is the two-rescuer ratio for infants/children, not adults.", "2": "2:30 reverses the ratio."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["30:2", "15:2", "2:30", "15:1"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A contraindication to a nasopharyngeal airway (NPA) is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-f9dzj", "exp": "A nasopharyngeal airway is contraindicated with a base-of-skull fracture, where it could pass through the fracture into the cranium. NPAs are otherwise useful in patients with an intact gag reflex (semi-conscious). Key takeaway: base-of-skull fracture = no NPA (same rule as nasal tubes).", "sub": "Nasopharyngeal Airway", "type": "mcq", "topic": "msn", "wrong": {"1": "A sedated patient may actually tolerate and benefit from an NPA.", "2": "Unconsciousness is not itself a contraindication to an NPA."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Skull base fracture", "Sedated patient", "Unconscious", "During dental procedures"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A complication of high-flow (high-pressure) ventilation is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-vp720", "exp": "Excessive ventilator pressure/volume causes barotrauma/volutrauma, which can rupture alveoli and produce a pneumothorax. Key takeaway: over-pressurising the lungs = barotrauma = pneumothorax.", "sub": "Mechanical Ventilation", "type": "mcq", "topic": "msn", "wrong": {"0": "Aspiration relates to airway protection, not ventilator pressure.", "3": "COPD is a chronic disease, not an acute ventilation complication."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["Aspiration", "Pneumothorax", "Diaphragmatic hernia", "COPD"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A patient has a calcium level of 7 mg/dL. Identify the ECG change seen in this patient:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-re7u4", "exp": "Calcium 7 mg/dL is hypocalcaemia, which prolongs the QT interval (by lengthening the ST segment). Key takeaway: low calcium = long QT; high calcium = short QT.", "sub": "ECG / Calcium", "type": "mcq", "topic": "msn", "wrong": {"2": "Prominent/peaked T waves are the classic sign of HYPERkalaemia, not hypocalcaemia.", "3": "U waves are linked to hypokalaemia, not low calcium."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["T-wave inversion", "Prolonged QT interval", "Prominent T wave", "Peaked U wave"], "difficulty": "hard", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "Interpret the following ABG: pH 7.25, pCO2 40 mmHg, HCO3 low. Identify the abnormality.", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-9i8we", "exp": "A low pH (7.25) with a normal pCO2 (40) cannot be a respiratory problem, so the acidosis is metabolic (low bicarbonate). Key takeaway: low pH + normal CO2 = metabolic acidosis; the lungs aren''t the culprit when CO2 is normal. NOTE: the source paper''s printed HCO3 value looks inconsistent — a true pH of 7.25 at pCO2 40 requires HCO3 around 17. The interpretation (metabolic acidosis) still holds; the printed figure looks like a transcription error.", "sub": "Arterial Blood Gas (FLAGGED – inconsistent values in source)", "type": "mcq", "topic": "msn", "wrong": {"1": "Respiratory acidosis would require a RAISED pCO2 (>45); here it''s normal.", "2": "Metabolic alkalosis would show a HIGH pH, not 7.25."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Metabolic acidosis", "Respiratory acidosis", "Metabolic alkalosis", "Respiratory alkalosis"], "difficulty": "hard", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "During suctioning, the patient complains of respiratory distress. The first nursing action should be:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-rij3q", "exp": "Suctioning withdraws oxygen along with secretions and can trigger hypoxia/distress, so the immediate action is to stop and remove the catheter, then re-oxygenate the patient. Key takeaway: suction-induced distress = stop suctioning and oxygenate first.", "sub": "Airway Suctioning", "type": "mcq", "topic": "fund", "wrong": {"1": "Continuing to suction (even briefly) prolongs the hypoxia causing the distress.", "3": "Calling the doctor delays the immediate, life-saving step of stopping and oxygenating."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Immediately remove the suction catheter", "Suction rapidly within 5 seconds and remove the catheter", "Call the senior nurse", "Call the doctor immediately"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "The earliest sign of hypocalcaemia is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-9w4wx", "exp": "Low calcium increases neuromuscular excitability, producing early tingling and muscle twitching (progressing to a positive Chvostek''s/Trousseau''s sign and tetany). Twitching is the early manifestation here. Key takeaway: low calcium = twitchy nerves — tingling and twitching first.", "sub": "Hypocalcaemia", "type": "mcq", "topic": "msn", "wrong": {"1": "A NEGATIVE Chvostek''s sign would suggest normal calcium; in hypocalcaemia it is POSITIVE.", "2": "Generalised weakness is non-specific and not the earliest neuromuscular-irritability sign."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Twitching", "Negative Chvostek''s sign", "Weakness", "Exaggerated deep tendon reflexes"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A patient has vitals: BP 120/66, Pulse 88, SpO2 99%, RR 23. This patient should be classified in which triage category?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-nmdh3", "exp": "All vitals are essentially normal/stable, so the patient is low-acuity — Green (minor, can wait). Key takeaway: stable vitals = Green; Red = immediate/critical, Black = deceased/unsalvageable.", "sub": "Triage", "type": "mcq", "topic": "fund", "wrong": {"0": "Red is reserved for unstable, immediately life-threatened patients.", "3": "Black is for the deceased or non-survivable — not a stable patient."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["Red", "Yellow", "Green", "Black"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A patient has Temp 104°F, BP 140/90 mmHg, RR 28/min, pain scale 5. Which factor will you primarily manage?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-dcekt", "exp": "By the ABC framework, breathing comes before everything else — and an RR of 28 is significant tachypnoea (a respiratory red flag), so it is managed first. Fever, mildly raised BP and moderate pain are addressed after the breathing is secured. Key takeaway: ABC — a markedly abnormal respiratory rate is prioritised over fever, BP and pain.", "sub": "Clinical Prioritisation", "type": "mcq", "topic": "fund", "wrong": {"0": "Fever matters, but a compromised respiratory rate takes ABC priority.", "3": "Pain of 5/10 is managed after the airway/breathing concern is addressed."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["Temp 104°F", "BP 140/90 mmHg", "RR 28/min", "Pain scale 5"], "difficulty": "hard", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A patient has Temp 103°F, HR 110/min, RR 23/min, BP 132/66 mmHg. Which factor will you primarily manage?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-lralx", "exp": "Here the RR (23) is only mildly elevated and the BP is normal, while the temperature is high at 103°F — and the fever is likely driving the tachycardia. So the most significant, treatable derangement is the hyperpyrexia: manage the temperature. Key takeaway: prioritise the most physiologically dangerous abnormal value — with breathing near-normal, the high fever leads (contrast with the previous item, where RR 28 led).", "sub": "Clinical Prioritisation", "type": "mcq", "topic": "fund", "wrong": {"1": "HR 110 is mild tachycardia, mostly secondary to the fever — treat the cause.", "2": "RR 23 is only slightly elevated and not the leading concern here."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Temp 103°F", "HR 110/min", "RR 23/min", "BP 132/66 mmHg"], "difficulty": "hard", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "According to ABC, which of the following describes improper cardiac circulation?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-z4l4m", "exp": "In the ABC primary survey, circulation is assessed first and foremost by the pulse — a diminished/weak pulse signals poor cardiac output/perfusion. (CRT <3 s is actually normal, and tachypnoea is a breathing sign.) Key takeaway: ''C'' = check the pulse; a weak pulse means poor circulation.", "sub": "ABC Assessment", "type": "mcq", "topic": "fund", "wrong": {"2": "Tachypnoea is a ''B'' (breathing) finding, not a circulation sign.", "3": "CRT < 3 seconds is NORMAL perfusion — the opposite of improper circulation."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["Hypotension", "Diminished pulse", "Tachypnoea", "Capillary refill time < 3 seconds"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "During IV administration, which of the following drugs causes extravasation and damage to the site?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-hzs92", "exp": "IV phenytoin is highly alkaline and a classic vesicant; extravasation causes severe local injury — the ''purple glove syndrome'' (swelling, discolouration, ischaemia of the distal limb). Key takeaway: phenytoin = vesicant; give through a patent, well-secured large vein, ideally with saline flush. (Epinephrine extravasation also causes necrosis — phenytoin is the textbook answer here.)", "sub": "IV Drug Safety", "type": "mcq", "topic": "pharm", "wrong": {"0": "Diazepam can cause phlebitis but isn''t the classic extravasation vesicant.", "3": "Ranitidine is generally well tolerated IV and not a vesicant."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["Diazepam", "Epinephrine", "Phenytoin", "Ranitidine"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "In a 3-year-old child, which of the following is the best complementary feed that can be given to this child?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-swi4v", "exp": "Dal rice provides a balance of carbohydrate (energy) and protein (from the dal) plus the protein-quality boost from combining cereal + pulse — making it an ideal staple complementary feed for a toddler. Key takeaway: cereal + pulse (e.g. dal-rice/khichdi) = complete, energy- and protein-dense meal for toddlers.", "sub": "Complementary Feeding", "type": "mcq", "topic": "nutr", "wrong": {"0": "Mashed bananas alone are low in protein and not a complete meal.", "2": "Fruit juice is mostly sugar and water — low protein, low energy density, fills the stomach without nourishing."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["Mashed bananas", "Dal rice", "Fruit juice", "Boiled soft carrot"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "A child is on CPAP and is hemodynamically stable. Which of the following is the best method of feeding this child?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-69w0p", "exp": "On CPAP, oral feeding (breast or cup) carries an aspiration risk because the child can''t safely coordinate sucking, swallowing and breathing against positive pressure. Nasogastric feeding delivers enteral nutrition safely while the airway support continues. Key takeaway: child on CPAP and stable → NG feeding (preserves the gut, avoids aspiration).", "sub": "Feeding on CPAP", "type": "mcq", "topic": "peds", "wrong": {"0": "Breastfeeding on CPAP is unsafe (aspiration risk and disrupts the seal).", "3": "IV fluids skip the gut; if the gut works (hemodynamically stable), feed it via NG."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["Breastfeeding", "Nasogastric feeding", "Cup feeding", "IV fluids"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "In a 4.5 mm endotracheal tube, what size of suction catheter is used?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-qo126", "exp": "Suction catheter size in Fr is roughly twice the ETT internal diameter in mm; for a 4.5 mm tube that''s about 9 Fr, so use the next size DOWN that still fits — 8 Fr. Going larger occludes the tube and worsens hypoxia. Key takeaway: catheter Fr ≈ 2 × ETT (mm), then round down.", "sub": "ET Tube / Suction Catheter Sizing", "type": "mcq", "topic": "peds", "wrong": {"0": "10 Fr is too large for a 4.5 mm tube — risks complete occlusion.", "2": "15 Fr would block the airway entirely."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [3], "options": ["10 French (Fr)", "12 French (Fr)", "15 French (Fr)", "8 French (Fr)"], "difficulty": "hard", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "The normal interval of the QRS complex is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-v4jnd", "exp": "A normal QRS duration is roughly 0.06–0.10 seconds; 0.08 sec sits in the middle of this range. >0.12 sec is considered wide (bundle branch block, ventricular origin). Key takeaway: normal QRS < 0.12 sec; 0.08 sec is the typical adult value.", "sub": "ECG Intervals", "type": "mcq", "topic": "msn", "wrong": {"1": "0.12 sec is the UPPER limit/cut-off for normal, not the typical value.", "2": "0.16 sec is already a wide (abnormal) QRS."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["0.08 sec", "0.12 sec", "0.16 sec", "0.4 sec"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "Flow rate of a drug is shown as 50 mL in 15 min. The correct flow rate of this drug is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-p0910", "exp": "50 mL in 15 minutes × (60 / 15) = 50 × 4 = 200 mL/hour. Key takeaway: convert to mL/hr by multiplying the per-minute (or per-fraction-hour) volume to a full 60 minutes.", "sub": "IV Flow Rate Calculation", "type": "mcq", "topic": "fund", "wrong": {"0": "150 mL/hr would be 37.5 mL in 15 min, not 50.", "1": "50 mL/hr would mean 50 mL over a full hour, not 15 minutes."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [2], "options": ["150 mL/hour", "50 mL/hour", "200 mL/hour", "100 mL/hour"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "For a patient, the desired dose of a drug is 200 mg BD. The available dose of this drug is 0.1 gm. The correct dosage for one dose of this drug is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-1c3lk", "exp": "0.1 g per tablet = 100 mg per tablet. Desired (200 mg) ÷ Available (100 mg/tab) = 2 tablets per dose. Key takeaway: standardise units first (g ↔ mg), then divide desired ÷ available.", "sub": "Dosage Calculation", "type": "mcq", "topic": "pharm", "wrong": {"0": "1 tab gives only 100 mg, half the desired dose.", "2": "3 tabs give 300 mg — overdose."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["1 tab", "2 tab", "3 tab", "4 tab"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "The desired dose of morphine for a patient is 0.4 mg. The dose available is 1 mg/mL. The correct volume for this patient is:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-wmy45", "exp": "Volume = Desired (0.4 mg) ÷ Concentration (1 mg/mL) = 0.4 mL. Key takeaway: when concentration is 1 mg/mL, the volume in mL equals the dose in mg.", "sub": "Dosage Calculation", "type": "mcq", "topic": "pharm", "wrong": {"1": "0.8 mL would deliver 0.8 mg — double the desired dose.", "2": "0.2 mL would deliver only 0.2 mg — half the desired."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["0.4 mL", "0.8 mL", "0.2 mL", "0.3 mL"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "Cefuroxime sodium 1 g in 50 mL normal saline is to be administered over 30 minutes to a client with an infection. The drop factor is 15 drops (gtt)/1 mL. The nurse sets the flow rate at how many drops per minute?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-7127d", "exp": "Drops/min = (50 mL × 15 gtt/mL) ÷ 30 min = 750 ÷ 30 = 25 gtt/min. Key takeaway: drop rate formula = (volume × drop factor) ÷ time (min).", "sub": "IV Drip Rate", "type": "mcq", "topic": "fund", "wrong": {"0": "22 gtt/min underdelivers — wouldn''t finish in 30 minutes.", "3": "30 gtt/min would finish too early (in 25 minutes)."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["22 gtt/min", "25 gtt/min", "28 gtt/min", "30 gtt/min"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "The healthcare provider is caring for a patient on a ventilator with an endotracheal tube in place. What assessment data indicates the tube has migrated too far down the trachea?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-uxhtx", "exp": "If the ETT advances past the carina it almost always enters the right main bronchus (which is wider, shorter and more vertical), ventilating only the right lung. Result: decreased breath sounds on the LEFT. Key takeaway: ETT ''too deep'' = right mainstem intubation = quiet left chest.", "sub": "Endotracheal Tube Position", "type": "mcq", "topic": "msn", "wrong": {"1": "A high-pressure alarm signals airway obstruction/biting/secretions, not specifically a deep tube.", "3": "Low-pressure alarm suggests a leak or disconnection, not migration."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [0], "options": ["Decreased breath sounds on the left side of the chest", "A high-pressure alarm sounds", "Increased crackles on auscultation bilaterally", "Low-pressure alarm sounds"], "difficulty": "hard", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "Which of the following layers of the adrenal gland secretes glucocorticoids?", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-oq4tq", "exp": "From outside in, the adrenal cortex has zona Glomerulosa (mineralocorticoids — Salt), zona Fasciculata (glucocorticoids — Sugar) and zona Reticularis (androgens — Sex). So glucocorticoids come from the zona fasciculata. Key takeaway: GFR = Salt, Sugar, Sex → Sugar is the middle zone (fasciculata).", "sub": "Adrenal Cortex", "type": "mcq", "topic": "anat", "wrong": {"0": "The adrenal MEDULLA secretes catecholamines (adrenaline/noradrenaline), not glucocorticoids.", "1": "Zona glomerulosa secretes mineralocorticoids (aldosterone), not glucocorticoids."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [3], "options": ["Adrenal medulla", "Zona glomerulosa", "Zona reticularis", "Zona fasciculata"], "difficulty": "medium", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}, {"q": "WHO declared COVID-19 a Public Health Emergency of International Concern (PHEIC) on:", "id": "bankq-bk-1779906243757-gua4df-bank-1779906236873-vqprj", "exp": "WHO declared COVID-19 a Public Health Emergency of International Concern (PHEIC) on 30 January 2020 (and later declared it a pandemic on 11 March 2020). Key takeaway: PHEIC = 30 Jan 2020; pandemic = 11 Mar 2020.", "sub": "COVID-19 / Public Health", "type": "mcq", "topic": "ch", "wrong": {"0": "13 Jan 2020 was around when WHO first published guidance, not the PHEIC date.", "3": "20 Jan 2020 predates the PHEIC declaration."}, "custom": true, "source": "AIIMS NORCET 2024 PYQ", "correct": [1], "options": ["13/01/2020", "30/01/2020", "31/01/2020", "20/01/2020"], "difficulty": "easy", "sourceBank": "bk-1779906243757-gua4df", "sourceBankName": "NORCET PYQs", "sourceBankVersion": 1}], "bankVersionsSeen": {"bk-1779906243757-gua4df": 1}, "bankPublishedSeen": {"bk-1779906243757-gua4df": 1779906243757}, "advancedTestHistory": [], "feedbackRepliesSeen": {}, "dismissedAnnouncementId": null}, "createdAt": 1779910061711, "displayName": "Nancy"}'),
